"""Mobile-first Balkan.works super-app shell.

The page intentionally keeps the five product areas in one persistent bottom
navigation. Individual services remain independent API modules behind it.
"""

from __future__ import annotations


def render_superapp_page(language: str = "SR", initial_tab: str = "home", initial_module: str = "") -> str:
    language = language if language in {"SR", "HR", "BS", "MK", "EN", "DE"} else "SR"
    tab = initial_tab if initial_tab in {"home", "explore", "rewards", "inbox", "profile"} else "home"
    template = r'''<!doctype html><html lang="__LANG__"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"><title>Balkan.works</title><style>
:root{--ink:#092c26;--pine:#0d4036;--paper:#f8f8f4;--card:#fff;--orange:#ff6c37;--mint:#e5f5eb;--line:#d9e3dc;--muted:#62746e;--nav:#ffffffef}*{box-sizing:border-box}body{margin:0;background:var(--paper);color:var(--ink);font-family:Inter,ui-sans-serif,system-ui,-apple-system,sans-serif}.shell{max-width:1440px;min-height:100vh;margin:auto;background:var(--paper);padding:0 16px calc(96px + env(safe-area-inset-bottom))}.top{height:74px;display:flex;align-items:center;justify-content:space-between}.brand{font-weight:950;font-size:24px;letter-spacing:-1.2px;color:var(--ink);text-decoration:none}.brand i{color:var(--orange);font-style:normal}.locale{appearance:none;border:1px solid var(--line);border-radius:10px;background:var(--card);padding:9px 10px;color:var(--pine);font-size:12px;font-weight:800}.view{display:none;padding-bottom:20px}.view.active{display:block}.eyebrow{font-size:11px;text-transform:uppercase;letter-spacing:1.4px;color:var(--orange);font-weight:900}.hero{background:linear-gradient(135deg,#0d4036,#165b4a);color:#fff;border-radius:23px;padding:25px;overflow:hidden;position:relative}.hero:after{content:'';position:absolute;width:220px;height:220px;border-radius:50%;right:-95px;top:-88px;background:#b8eea71c}.hero h1{font:38px/.98 Georgia,serif;letter-spacing:-1.8px;margin:12px 0;max-width:400px}.hero p{max-width:430px;margin:0;color:#d6e6de;line-height:1.5;font-size:14px}.location{display:flex;gap:8px;margin-top:18px;align-items:center;position:relative;z-index:1}.location input{flex:1;min-width:0;border:0;border-radius:10px;padding:12px;font:inherit;color:var(--ink)}button{font:inherit;cursor:pointer}.locate,.primary{border:0;border-radius:10px;background:var(--orange);color:#fff;padding:12px 13px;font-weight:850}.section{margin:28px 0}.section-head{display:flex;align-items:flex-end;justify-content:space-between;gap:12px;margin-bottom:13px}.section-head h2{font:27px Georgia,serif;letter-spacing:-1px;margin:4px 0 0}.link{border:0;background:none;color:var(--orange);font-weight:850;font-size:13px}.feed{display:flex;gap:12px;overflow:auto;scrollbar-width:none;padding-bottom:4px}.feed::-webkit-scrollbar{display:none}.feed-card{min-width:238px;background:var(--card);border:1px solid var(--line);border-radius:16px;padding:16px;text-decoration:none;color:var(--ink);display:flex;flex-direction:column;gap:8px;min-height:160px}.feed-card strong{font-size:16px;line-height:1.18}.feed-card p{font-size:12px;color:var(--muted);margin:0;line-height:1.45}.tag{font-size:10px;font-weight:900;color:#18704f;background:var(--mint);border-radius:99px;padding:5px 8px;width:max-content}.feed-card .cta{margin-top:auto;color:var(--orange);font-size:12px;font-weight:850}.empty{background:var(--card);border:1px dashed var(--line);border-radius:14px;padding:18px;color:var(--muted);font-size:13px}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.module{border:1px solid var(--line);border-radius:17px;background:var(--card);padding:16px;min-height:162px;text-align:left;color:var(--ink);text-decoration:none;display:flex;flex-direction:column;gap:8px}.module .ico{font-size:25px}.module strong{font-size:16px}.module small{color:var(--muted);font-size:12px;line-height:1.4}.module span:last-child{margin-top:auto;color:var(--orange);font-size:12px;font-weight:850}.search{display:flex;gap:8px;background:var(--card);padding:8px;border:1px solid var(--line);border-radius:13px}.search input{border:0;outline:0;flex:1;font:inherit;min-width:0}.search button{border:0;border-radius:9px;background:var(--pine);color:#fff;font-weight:850;padding:9px 12px}.result{margin-top:13px;display:grid;gap:9px}.result article,.panel,.thread{border:1px solid var(--line);background:var(--card);border-radius:15px;padding:15px}.result h3,.thread h3{font-size:15px;margin:0 0 5px}.result p,.thread p{font-size:13px;color:var(--muted);margin:0;line-height:1.45}.reward-card{border-radius:20px;background:linear-gradient(135deg,#ff6c37,#f8903e);color:#fff;padding:23px}.reward-card h1{font:45px Georgia,serif;margin:7px 0 0}.reward-card p{margin:5px 0;color:#fff0e8;font-size:13px}.reward-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:9px;margin-top:12px}.reward-grid div{background:#ffffff22;border:1px solid #ffffff37;border-radius:12px;padding:11px}.reward-grid b{display:block;font-size:17px}.reward-grid span{font-size:10px;color:#fff4ef}.coupon{background:var(--card);border:1px dashed var(--orange);border-radius:14px;padding:16px;margin-top:12px}.coupon h3{margin:0 0 5px;font-size:16px}.coupon p{margin:0;color:var(--muted);font-size:13px}.inbox-tabs{display:flex;gap:8px;overflow:auto;margin-bottom:13px}.chip{white-space:nowrap;border:1px solid var(--line);background:#fff;color:var(--pine);border-radius:999px;padding:8px 11px;font-size:12px;font-weight:850}.chip.active{background:var(--pine);color:#fff;border-color:var(--pine)}.compose{display:grid;gap:9px}.compose input,.compose textarea{border:1px solid var(--line);border-radius:10px;padding:12px;font:inherit;resize:vertical}.composer-actions{display:flex;gap:8px}.secondary{border:1px solid var(--pine);background:#fff;color:var(--pine);border-radius:10px;padding:11px 13px;font-weight:850}.profile-head{background:var(--card);border:1px solid var(--line);border-radius:18px;padding:18px;display:flex;gap:13px;align-items:center}.avatar{height:52px;width:52px;border-radius:50%;display:grid;place-items:center;background:var(--mint);color:#18704f;font-size:22px;font-weight:900}.profile-head h1{font:27px Georgia,serif;margin:0}.profile-head p{margin:4px 0 0;color:var(--muted);font-size:13px}.rows{margin-top:13px;border:1px solid var(--line);border-radius:15px;background:var(--card);overflow:hidden}.row{display:flex;justify-content:space-between;align-items:center;padding:15px;border-bottom:1px solid var(--line);font-size:14px}.row:last-child{border:0}.row b{font-size:13px}.row span{font-size:12px;color:var(--muted)}.notice{font-size:13px;color:var(--muted);margin-top:9px}.bottom{position:fixed;z-index:5;left:50%;bottom:0;transform:translateX(-50%);width:min(1440px,100%);padding:9px 12px calc(9px + env(safe-area-inset-bottom));background:var(--nav);border-top:1px solid var(--line);display:grid;grid-template-columns:repeat(5,1fr);backdrop-filter:blur(12px)}.navitem{border:0;background:transparent;color:var(--muted);padding:7px 2px;display:grid;justify-items:center;gap:3px;font-size:10px}.navitem b{font-size:21px;line-height:1;font-weight:500}.navitem.active{color:var(--orange);font-weight:900}.modal{position:fixed;inset:0;background:#092c2668;z-index:10;display:none;align-items:end}.modal.open{display:flex}.modal-card{width:min(1440px,100%);margin:auto;background:#fff;border-radius:22px 22px 0 0;padding:22px 18px calc(25px + env(safe-area-inset-bottom));max-height:86vh;overflow:auto}.modal-card h2{font:29px Georgia,serif;margin:5px 0 14px}.close{float:right;border:0;background:var(--paper);height:34px;width:34px;border-radius:50%;font-size:20px}.login{width:100%;margin-top:12px}.local-event{display:flex;gap:10px}.date{min-width:52px;border-radius:10px;padding:8px;background:var(--mint);color:#18704f;text-align:center;font-size:11px;font-weight:900}.date b{display:block;font-size:19px}@media(min-width:780px){.shell{padding-left:40px;padding-right:40px}.grid{grid-template-columns:repeat(3,1fr)}.hero{min-height:300px;padding:44px;display:grid;align-content:center}.hero:after{width:430px;height:430px;right:-110px;top:-150px}.hero h1{font-size:56px;max-width:650px}.hero p{font-size:16px;max-width:590px}.feed{display:grid;grid-template-columns:repeat(3,1fr);overflow:visible}.feed-card{min-width:0}.bottom{border:1px solid var(--line);border-bottom:0;border-radius:20px 20px 0 0}}@media(min-width:1120px){.grid{grid-template-columns:repeat(4,1fr)}.feed{grid-template-columns:repeat(4,1fr)}.view#profile{max-width:840px}.view#rewards{max-width:980px}.view#inbox{max-width:980px}}
</style></head><body><div class="shell"><header class="top"><a class="brand" href="/">balkan<i>.</i>works</a><select class="locale" id="locale"><option>SR</option><option>HR</option><option>BS</option><option>MK</option><option>EN</option><option>DE</option></select></header>
<main>
<section class="view" id="home"><div class="hero"><div class="eyebrow">Balkan.works Home</div><h1>Svaki dan nešto korisno, blizu tebe.</h1><p>Akcije, Save Food, poslovi, majstori i događaji u jednom personalizovanom toku.</p><div class="location"><input id="home-city" placeholder="Tvoj grad, npr. Novi Sad"><button class="locate" id="use-gps">⌖ GPS</button></div></div><section class="section"><div class="section-head"><div><div class="eyebrow">Za tebe</div><h2>U blizini</h2></div><button class="link" data-tab="explore">Istraži sve →</button></div><div class="feed" id="nearby-feed"><div class="empty">Učitavamo lokalne sadržaje…</div></div></section><section class="section"><div class="section-head"><div><div class="eyebrow">Danas na platformi</div><h2>Brze prečice</h2></div></div><div class="grid"><a class="module" href="/deals"><span class="ico">◈</span><strong>Akcije i flajeri</strong><small>Digitalni katalozi i cene iz lokalnih prodavnica.</small><span>Otvori Deals →</span></a><a class="module" href="/save-food"><span class="ico">◌</span><strong>Save Food</strong><small>Rezerviši dobre pakete hrane u svom gradu.</small><span>Vidi ponude →</span></a><a class="module" href="/market"><span class="ico">⌁</span><strong>Poslovi i usluge</strong><small>Majstori, servisi i lokalna pomoć.</small><span>Pronađi lokalno →</span></a></div></section></section>
<section class="view" id="explore"><div class="eyebrow">Explore</div><h1 style="font:38px Georgia,serif;margin:7px 0 17px">Istraži ceo Balkan.works.</h1><div class="search"><input id="search-q" placeholder="Pretraži usluge, ponude i firme"><button id="search-go">Pretraži</button></div><div class="result" id="search-results"></div><section class="section"><div class="grid"><a class="module" href="/save-food"><span class="ico">◌</span><strong>Save Food</strong><small>Hrana koja zaslužuje drugu šansu.</small><span>Otvori →</span></a><a class="module" href="/deals"><span class="ico">◈</span><strong>Flajeri i Deals</strong><small>Akcije, kuponi i katalozi.</small><span>Otvori →</span></a><a class="module" href="/market"><span class="ico">⌁</span><strong>Poslovi</strong><small>Lokalni i freelance poslovi.</small><span>Otvori →</span></a><a class="module" href="/market"><span class="ico">⚒</span><strong>Usluge</strong><small>Majstori i servisne usluge.</small><span>Otvori →</span></a><a class="module" href="/market"><span class="ico">▦</span><strong>Marketplace</strong><small>Proizvodi, oglasi i firme.</small><span>Otvori →</span></a><button class="module" data-tab="profile"><span class="ico">⌘</span><strong>Finansije</strong><small>Wallet, budžet i Money modul.</small><span>Otvori Money →</span></button><button class="module" id="local-open"><span class="ico">◎</span><strong>Balkan Local</strong><small>Koncerti, festivali, sajmovi i sport.</small><span>Vidi događaje →</span></button></div></section></section>
<section class="view" id="rewards"><div class="eyebrow">Balkan Rewards</div><h1 style="font:38px Georgia,serif;margin:7px 0 17px">Svaka dobra odluka se računa.</h1><div class="reward-card"><span class="eyebrow" style="color:#fff4ef">Tvoj Rewards balans</span><h1 id="reward-points">—</h1><p>poena na jednom Balkan ID nalogu</p><div class="reward-grid"><div><b id="reward-tier">—</b><span>status</span></div><div><b id="reward-cashback">—</b><span>cashback</span></div><div><b id="reward-wallet">—</b><span>wallet</span></div></div></div><div class="coupon"><h3>Kuponi i nagrade</h3><p id="coupon-note">Prijavi se da vidiš svoje poene, kupone i pogodnosti iz svih modula.</p></div></section>
<section class="view" id="inbox"><div class="eyebrow">Inbox</div><h1 style="font:38px Georgia,serif;margin:7px 0 17px">Sve važne poruke, zajedno.</h1><div class="inbox-tabs"><button class="chip active" data-inbox="messages">Poruke</button><button class="chip" data-inbox="notifications">Obaveštenja</button><button class="chip" data-inbox="support">Podrška</button><button class="chip" data-inbox="assistant">AI asistent</button></div><div id="inbox-content"><div class="empty">Prijavi se da vidiš svoje poruke.</div></div></section>
<section class="view" id="profile"><div class="eyebrow">Balkan ID</div><div class="profile-head"><div class="avatar" id="avatar">B</div><div><h1 id="profile-name">Tvoj Balkan ID</h1><p id="profile-subtitle">Jedan nalog za sve module.</p></div></div><div class="rows"><div class="row"><div><b>Wallet</b><br><span>Saldo i transakcije</span></div><strong id="profile-wallet">—</strong></div><div class="row"><div><b>Pretplate</b><br><span>Business i budući premium moduli</span></div><strong>Uskoro</strong></div><div class="row"><div><b>Podešavanja</b><br><span>Jezik, lokacija i privatnost</span></div><a href="/account" class="link">Uredi →</a></div></div><button class="primary login" id="profile-action">Prijavi se / napravi nalog</button><p class="notice" id="profile-note">Balkan ID povezuje Deals, Save Food, Marketplace, Rewards i Business.</p></section>
</main></div>
<nav class="bottom"><button class="navitem" data-tab="home"><b>⌂</b>Home</button><button class="navitem" data-tab="explore"><b>⌕</b>Explore</button><button class="navitem" data-tab="rewards"><b>◈</b>Rewards</button><button class="navitem" data-tab="inbox"><b>◌</b>Inbox</button><button class="navitem" data-tab="profile"><b>◉</b>Profile</button></nav>
<div class="modal" id="local-modal"><div class="modal-card"><button class="close" id="local-close">×</button><div class="eyebrow">Balkan Local</div><h2>Događaji u tvom kraju.</h2><div id="local-events"><div class="empty">Učitavamo događaje…</div></div></div></div>
<script>
const initialTab='__TAB__',initialModule='__MODULE__',token=()=>localStorage.getItem('balkan_access_token');const auth=()=>token()?{authorization:'Bearer '+token()}:{};const byId=id=>document.getElementById(id);const esc=v=>String(v??'').replace(/[&<>"']/g,x=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[x]));const money=(v,c='EUR')=>v==null?'Dogovor':Number(v).toLocaleString('sr-RS',{style:'currency',currency:c});async function api(url,opt={}){const r=await fetch(url,{...opt,headers:{...auth(),...(opt.headers||{})}}),d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.detail||'Zahtev nije uspeo.');return d}
function selectTab(name){document.querySelectorAll('.view').forEach(v=>v.classList.toggle('active',v.id===name));document.querySelectorAll('.navitem').forEach(v=>v.classList.toggle('active',v.dataset.tab===name));if(name==='home')loadHome();if(name==='rewards')loadRewards();if(name==='inbox')loadInbox('messages');if(name==='profile')loadProfile();window.scrollTo({top:0,behavior:'smooth'})}document.querySelectorAll('[data-tab]').forEach(b=>b.onclick=()=>selectTab(b.dataset.tab));
async function loadHome(){const city=byId('home-city').value.trim(),q=city?'?city_name='+encodeURIComponent(city):'';try{const [offers,food,market,events]=await Promise.all([api('/api/deals/offers'+q),api('/api/food/packages'),api('/api/market/listings'+q),api('/api/local/events'+q)]);const list=[];offers.slice(0,2).forEach(x=>list.push({tag:'DEALS',title:x.title,text:(x.city_name||x.country_code)+' · '+money(x.price,x.currency),url:'/deals'}));food.slice(0,2).forEach(x=>list.push({tag:'SAVE FOOD',title:x.title,text:'Preuzimanje · '+money(x.price,x.currency),url:'/save-food'}));market.slice(0,2).forEach(x=>list.push({tag:x.listing_type,title:x.title,text:(x.city_name||x.country_code)+' · '+money(x.price,x.currency),url:'/market'}));events.slice(0,2).forEach(x=>list.push({tag:'BALKAN LOCAL',title:x.title,text:x.city_name+' · '+new Date(x.starts_at).toLocaleDateString('sr-RS'),url:'#local'}));byId('nearby-feed').innerHTML=list.length?list.map(x=>'<a class="feed-card" href="'+x.url+'"><span class="tag">'+esc(x.tag)+'</span><strong>'+esc(x.title)+'</strong><p>'+esc(x.text)+'</p><span class="cta">Pogledaj →</span></a>').join(''):'<div class="empty">Još nema objava za ovu lokaciju. Promeni grad ili istraži sve module.</div>'}catch(e){byId('nearby-feed').innerHTML='<div class="empty">'+esc(e.message)+'</div>'}}
byId('use-gps').onclick=()=>{if(!navigator.geolocation){return}navigator.geolocation.getCurrentPosition(p=>{byId('home-city').placeholder='GPS lokacija je postavljena';localStorage.setItem('balkan_lat',p.coords.latitude);localStorage.setItem('balkan_lng',p.coords.longitude);loadHome()})};byId('home-city').onchange=()=>{localStorage.setItem('balkan_city',byId('home-city').value);loadHome()};byId('home-city').value=localStorage.getItem('balkan_city')||'';
byId('search-go').onclick=async()=>{const q=byId('search-q').value.trim();if(!q)return;byId('search-results').innerHTML='<div class="empty">Pretražujemo…</div>';try{const d=await api('/api/search?q='+encodeURIComponent(q));const values=Object.values(d).flat().slice(0,20);byId('search-results').innerHTML=values.length?values.map(x=>'<article><h3>'+esc(x.title||x.name||'Rezultat')+'</h3><p>'+esc(x.description||x.city_name||x.type||'Balkan.works')+'</p></article>').join(''):'<div class="empty">Nema rezultata. Pokušaj drugi naziv ili grad.</div>'}catch(e){byId('search-results').innerHTML='<div class="empty">'+esc(e.message)+'</div>'}};
async function loadRewards(){if(!token()){byId('reward-points').textContent='—';byId('reward-tier').textContent='Balkan ID';byId('reward-cashback').textContent='—';byId('reward-wallet').textContent='—';return}try{const d=await api('/api/super-app/hub');byId('reward-points').textContent=d.rewards.points;byId('reward-tier').textContent=d.rewards.tier;byId('reward-cashback').textContent='0,00 €';byId('reward-wallet').textContent=money(d.wallet.balance,d.wallet.currency);byId('coupon-note').textContent=d.rewards.note}catch(e){byId('coupon-note').textContent=e.message}}
async function loadInbox(kind){document.querySelectorAll('[data-inbox]').forEach(x=>x.classList.toggle('active',x.dataset.inbox===kind));const box=byId('inbox-content');if(!token()){box.innerHTML='<div class="empty">Prijavi se da koristiš poruke, podršku i Balkan Assistant.</div>';return}if(kind==='assistant'){box.innerHTML='<div class="panel"><h3>Balkan Assistant</h3><p>AI asistent je spreman da poveže pretragu iz svih modula čim se aktivira bezbedni OpenAI pristup.</p><button class="secondary" disabled>AI konfiguracija u toku</button></div>';return}try{if(kind==='messages'){const items=await api('/api/market/messages');box.innerHTML=items.length?items.map(x=>'<article class="thread"><h3>Poruka sa Marketplace-a</h3><p>'+esc(x.body)+'</p></article>').join(''):'<div class="empty">Još nema poruka. Kontakt sa firmama i majstorima stiže ovde.</div>'}if(kind==='notifications'){const items=await api('/api/notifications');box.innerHTML=items.length?items.map(x=>'<article class="thread"><h3>'+esc(x.title)+'</h3><p>'+esc(x.body)+'</p></article>').join(''):'<div class="empty">Nema novih obaveštenja.</div>'}if(kind==='support'){box.innerHTML='<div class="panel"><h3>Kontaktiraj podršku</h3><div class="compose"><input id="support-subject" placeholder="Tema"><textarea id="support-body" placeholder="Kako možemo da pomognemo?"></textarea><button class="primary" id="support-send">Pošalji zahtev</button></div><p class="notice" id="support-notice"></p></div>';byId('support-send').onclick=async()=>{try{await api('/api/support/tickets',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({subject:byId('support-subject').value,body:byId('support-body').value,module_key:'superapp'})});byId('support-notice').textContent='Zahtev je poslat. Odgovor stiže u Inbox.'}catch(e){byId('support-notice').textContent=e.message}}}}catch(e){box.innerHTML='<div class="empty">'+esc(e.message)+'</div>'}}document.querySelectorAll('[data-inbox]').forEach(x=>x.onclick=()=>loadInbox(x.dataset.inbox));
async function loadProfile(){if(!token()){byId('profile-name').textContent='Tvoj Balkan ID';byId('profile-subtitle').textContent='Jedan nalog za sve module.';byId('profile-action').textContent='Prijavi se / napravi nalog';byId('profile-action').onclick=()=>location.href='/account';return}try{const [me,wallet]=await Promise.all([api('/api/me'),api('/api/payments/wallet')]);byId('profile-name').textContent=me.profile.display_name;byId('profile-subtitle').textContent=me.user.email+' · '+(me.profile.city_name||'Podesi lokaciju');byId('avatar').textContent=(me.profile.display_name||'B')[0].toUpperCase();byId('profile-wallet').textContent=money(wallet.balance,wallet.currency);byId('profile-action').textContent='Uredi Balkan ID';byId('profile-action').onclick=()=>location.href='/account'}catch(e){byId('profile-note').textContent=e.message}}
async function loadLocal(){const box=byId('local-events');try{const events=await api('/api/local/events');box.innerHTML=events.length?events.map(x=>{const d=new Date(x.starts_at);return '<article class="thread local-event"><div class="date">'+d.toLocaleDateString('sr-RS',{month:'short'})+'<b>'+d.getDate()+'</b></div><div><h3>'+esc(x.title)+'</h3><p>'+esc(x.city_name)+' · '+esc(x.venue_name||'Lokacija uskoro')+' · '+esc(x.event_type)+'</p></div></article>'}).join(''):'<div class="empty">Još nema objavljenih događaja. Organizatori i lokalne firme će ih dodavati kroz Balkan Local.</div>'}catch(e){box.innerHTML='<div class="empty">'+esc(e.message)+'</div>'}}byId('local-open').onclick=()=>{byId('local-modal').classList.add('open');loadLocal()};byId('local-close').onclick=()=>byId('local-modal').classList.remove('open');byId('local-modal').onclick=e=>{if(e.target===byId('local-modal'))byId('local-modal').classList.remove('open')};
byId('locale').value='__LANG__';byId('locale').onchange=()=>{localStorage.setItem('balkan_locale',byId('locale').value)};if(initialModule==='local'){byId('local-modal').classList.add('open');loadLocal()}selectTab(initialTab);
</script></body></html>'''
    template = template.replace(
        '<div class="result" id="search-results"></div>',
        '<div class="result" id="search-results"></div><a class="module" href="/everyday" style="margin-top:14px;min-height:0"><span class="ico">◉</span><strong>Balkan Everyday</strong><small>Zdravlje, apoteke, računi, gorivo, parking, nekretnine, porodica i Green Score.</small><span>Otvori svakodnevne module →</span></a>',
    )
    return template.replace("__LANG__", language).replace("__TAB__", initial_tab).replace("__MODULE__", initial_module)
